            showForm = false;
            await LoadShipments();
        }
        catch (Exception ex)
        {
            errorMessage = $"Error saving shipment: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private async Task DeleteShipment(ShipmentDto shipment)
    {
        try
        {
            await ShipmentSvc.DeleteShipmentAsync(shipment.Id);
            await LoadShipments();
        }
        catch (Exception ex)
        {
            errorMessage = $"Error deleting shipment: {ex.Message}";
        }
