}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@rendermode InteractiveAuto
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

@inject ShipmentService ShipmentSvc

<PageTitle>Track Shipment</PageTitle>

<h2>Track Your Shipment</h2>

<div class="row justify-content-center mt-4">
    <div class="col-md-8">
        <div class="input-group input-group-lg mb-4">
            <input class="form-control" placeholder="Enter tracking number (e.g. TRK-20260501-001)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="Search" disabled="@searching">
                @(searching ? "Searching…" : "Track")
            </button>
        </div>

        @if (searched && shipment is null && !searching)
        {
            <div class="alert alert-warning">
                <strong>No shipment found</strong> for tracking number <code>@searchedNumber</code>.
                Please verify the number and try again.
            </div>
        }

        @if (shipment is not null)
        {
            <div class="card">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <h5 class="mb-0">Shipment <code>@shipment.TrackingNumber</code></h5>
                    <span class="badge @StatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span>
                </div>
                <div class="card-body">
                    <div class="row mb-3">
                        <div class="col-sm-6">
                            <strong>Origin:</strong> @shipment.Origin
                        </div>
                        <div class="col-sm-6">
                            <strong>Destination:</strong> @shipment.Destination
                        </div>
                    </div>
                    <div class="row mb-3">
                        <div class="col-sm-6">
                            <strong>Recipient:</strong> @shipment.RecipientName
                        </div>
                        <div class="col-sm-6">
                            <strong>Shipped:</strong> @shipment.ShippedDate.ToString("MMMM dd, yyyy")
                        </div>
                    </div>

                    <hr />

                    <div class="row">
                        <div class="col-sm-6">
                            <h6>Estimated Delivery</h6>
                            <p class="fs-4 fw-bold text-primary">
                                @shipment.EstimatedDelivery.ToString("MMMM dd, yyyy")
                            </p>
                            @if (shipment.Status != ShipmentStatus.Delivered)
                            {
                                var daysLeft = (shipment.EstimatedDelivery.Date - DateTime.UtcNow.Date).Days;
                                <p class="text-muted">
                                    @if (daysLeft > 0)
                                    {
                                        @($"{daysLeft} day(s) from now")
                                    }
                                    else if (daysLeft == 0)
                                    {
                                        <span class="text-success fw-bold">Arriving today</span>
                                    }
                                    else
                                    {
                                        <span class="text-danger">@($"Overdue by {Math.Abs(daysLeft)} day(s)")</span>
                                    }
                                </p>
                            }
                        </div>
                        <div class="col-sm-6">
                            @if (shipment.ActualDelivery.HasValue)
                            {
                                <h6>Actual Delivery</h6>
                                <p class="fs-4 fw-bold text-success">
                                    @shipment.ActualDelivery.Value.ToString("MMMM dd, yyyy")
                                </p>
                            }
                        </div>
                    </div>

                    @if (!string.IsNullOrWhiteSpace(shipment.Notes))
                    {
                        <hr />
                        <div>
                            <strong>Notes:</strong> @shipment.Notes
                        </div>
                    }

                    <!-- Progress visualization -->
                    <hr />
                    <h6>Shipment Progress</h6>
                    <div class="progress" style="height: 30px;">
                        <div class="progress-bar @ProgressBarClass(shipment.Status)"
                             role="progressbar"
                             style="width: @ProgressPercent(shipment.Status)%"
                             aria-valuenow="@ProgressPercent(shipment.Status)"
                             aria-valuemin="0" aria-valuemax="100">
                            @shipment.Status
                        </div>
                    </div>
                </div>
            </div>
        }
    </div>
</div>

