@page "/dispatcher"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@rendermode InteractiveAuto
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

@inject ShipmentService ShipmentSvc

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>Dispatcher Dashboard</h2>

<div class="mb-3 d-flex gap-2 align-items-end flex-wrap">
    <div>
        <label class="form-label">Filter by Status</label>
        <select class="form-select" @bind="statusFilter">
            <option value="">All</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div>
        <label class="form-label">Search</label>
        <input class="form-control" placeholder="Tracking # or destination…" @bind="searchTerm" @bind:event="oninput" />
    </div>
    <button class="btn btn-primary" @onclick="ShowCreateForm">+ New Shipment</button>
</div>

@if (showForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">@(editingShipment.Id == 0 ? "New Shipment" : "Edit Shipment")</h5>
            <EditForm Model="editingShipment" OnValidSubmit="SaveShipment" FormName="shipmentForm">
                <DataAnnotationsValidator />
                <div class="row g-3">
                    <div class="col-md-4">
                        <label class="form-label">Tracking #</label>
                        <InputText class="form-control" @bind-Value="editingShipment.TrackingNumber" disabled="@(editingShipment.Id != 0)" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Origin</label>
                        <InputText class="form-control" @bind-Value="editingShipment.Origin" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Destination</label>
                        <InputText class="form-control" @bind-Value="editingShipment.Destination" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Status</label>
                        <InputSelect class="form-select" @bind-Value="editingShipment.Status">
                            @foreach (var s in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@s">@s</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Shipped Date</label>
                        <InputDate class="form-control" @bind-Value="editingShipment.ShippedDate" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Est. Delivery</label>
                        <InputDate class="form-control" @bind-Value="editingShipment.EstimatedDelivery" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Actual Delivery</label>
                        <InputDate class="form-control" @bind-Value="editingShipment.ActualDelivery" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Recipient</label>
                        <InputText class="form-control" @bind-Value="editingShipment.RecipientName" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Customer Email</label>
                        <InputText class="form-control" @bind-Value="editingShipment.CustomerEmail" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Notes</label>
                        <InputText class="form-control" @bind-Value="editingShipment.Notes" />
                    </div>
                </div>
                <div class="mt-3 d-flex gap-2">
                    <button type="submit" class="btn btn-success" disabled="@saving">
                        @(saving ? "Saving…" : "Save")
                    </button>
                    <button type="button" class="btn btn-secondary" @onclick="CancelForm">Cancel</button>
                </div>
            </EditForm>
            @if (!string.IsNullOrEmpty(errorMessage))
            {
                <div class="alert alert-danger mt-2">@errorMessage</div>
            }
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments…</em></p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Shipped</th>
                    <th>Est. Delivery</th>
                    <th>Recipient</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td><span class="badge @StatusBadgeClass(s.Status)">@s.Status</span></td>
                        <td>@s.ShippedDate.ToString("MMM dd, yyyy")</td>
                        <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                        <td>@s.RecipientName</td>
                        <td>
                            <button class="btn btn-sm btn-outline-primary" @onclick="() => EditShipment(s)">Edit</button>
                            <button class="btn btn-sm btn-outline-danger" @onclick="() => DeleteShipment(s)">Delete</button>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<ShipmentDto>? shipments;
    private string statusFilter = "";
    private string searchTerm = "";
    private bool showForm;
    private bool saving;
    private string? errorMessage;
    private ShipmentDto editingShipment = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await ShipmentSvc.GetAllShipmentsAsync();
    }

    private IEnumerable<ShipmentDto> FilteredShipments
    {
        get
        {
            if (shipments is null) return [];
            var result = shipments.AsEnumerable();

            if (Enum.TryParse<ShipmentStatus>(statusFilter, out var status))
                result = result.Where(s => s.Status == status);

            if (!string.IsNullOrWhiteSpace(searchTerm))
                result = result.Where(s =>
                    s.TrackingNumber.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
                    s.Destination.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
                    s.RecipientName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));

            return result;
        }
    }

    private void ShowCreateForm()
    {
        editingShipment = new ShipmentDto
        {
            TrackingNumber = $"TRK-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(100, 999)}",
            ShippedDate = DateTime.UtcNow,
            EstimatedDelivery = DateTime.UtcNow.AddDays(5)
        };
        showForm = true;
        errorMessage = null;
    }

    private void EditShipment(ShipmentDto shipment)
    {
        editingShipment = new ShipmentDto
        {
            Id = shipment.Id,
            TrackingNumber = shipment.TrackingNumber,
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            Status = shipment.Status,
            ShippedDate = shipment.ShippedDate,
            EstimatedDelivery = shipment.EstimatedDelivery,
            ActualDelivery = shipment.ActualDelivery,
            RecipientName = shipment.RecipientName,
            CustomerEmail = shipment.CustomerEmail,
            Notes = shipment.Notes
        };
        showForm = true;
        errorMessage = null;
    }

    private async Task SaveShipment()
    {
        saving = true;
        errorMessage = null;
        try
        {
            if (editingShipment.Id == 0)
                await ShipmentSvc.CreateShipmentAsync(editingShipment);
            else
                await ShipmentSvc.UpdateShipmentAsync(editingShipment);

            showForm = false;
            await LoadShipments();
        }
        catch (Exception ex)
        {
            errorMessage = $"Error saving shipment: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private async Task DeleteShipment(ShipmentDto shipment)
    {
        try
        {
            await ShipmentSvc.DeleteShipmentAsync(shipment.Id);
            await LoadShipments();
        }
        catch (Exception ex)
        {
            errorMessage = $"Error deleting shipment: {ex.Message}";
        }
    }

    private void CancelForm() => showForm = false;

    private static string StatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Exception => "bg-danger",
        _ => "bg-secondary"
    };
}

